import requests
import pytest

@pytest.mark.usefixtures('employee_token', 'db_session')
def test_non_hr_admin_role_cannot_view_timesheet(employee_token, db_session, api_url):
    headers = {'Authorization': f'Bearer {employee_token}'}
    response = requests.get(f'{api_url}/timesheets/ts-001', headers=headers)
    assert response.status_code == 403
    assert 'forbidden' in response.text.lower() or 'permission' in response.text.lower()
    audit_record = db_session.query(AuditLog).filter_by(
        action='VIEW', resource_id='ts-001'
    ).order_by(AuditLog.created_at.desc()).first()
    assert audit_record is None

